## File Integrity Monitor (FIM) — Python

Berikut script FIM yang komprehensif:

```python
#!/usr/bin/env python3
"""
File Integrity Monitor (FIM)
Memonitor perubahan file kritis dan mengirim alert
"""

import os
import hashlib
import json
import time
import logging
import smtplib
from pathlib import Path
from datetime import datetime
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart

# Konfigurasi
CONFIG = {
    'monitored_paths': [
        '/etc/passwd',
        '/etc/shadow',
        '/etc/sudoers',
        '/etc/ssh/sshd_config',
        '/var/www/html',
        '/etc/crontab',
        '/etc/hosts',
    ],
    'baseline_file': '/var/fim/baseline.json',
    'log_file': '/var/log/fim.log',
    'check_interval': 300,  # 5 menit
    'alert_email': 'security@perusahaan.co.id',
    'smtp_server': 'smtp.gmail.com',
    'smtp_port': 587,
}

# Setup logging
logging.basicConfig(
    filename=CONFIG['log_file'],
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger('FIM')


def calculate_hash(filepath: str, algorithm='sha256') -> str:
    """Hitung hash file dengan SHA256"""
    h = hashlib.new(algorithm)
    try:
        with open(filepath, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                h.update(chunk)
        return h.hexdigest()
    except (PermissionError, FileNotFoundError) as e:
        logger.warning(f'Tidak bisa baca {filepath}: {e}')
        return None


def get_file_metadata(filepath: str) -> dict:
    """Ambil metadata file: hash, size, permissions, owner"""
    try:
        stat = os.stat(filepath)
        return {
            'hash': calculate_hash(filepath),
            'size': stat.st_size,
            'permissions': oct(stat.st_mode),
            'uid': stat.st_uid,
            'gid': stat.st_gid,
            'mtime': stat.st_mtime,
            'ctime': stat.st_ctime,
        }
    except OSError as e:
        logger.error(f'Error metadata {filepath}: {e}')
        return None


def scan_directory(dirpath: str) -> dict:
    """Scan seluruh direktori secara rekursif"""
    results = {}
    for root, dirs, files in os.walk(dirpath):
        # Skip direktori tersembunyi (kecuali .ssh)
        dirs[:] = [d for d in dirs if not d.startswith('.') or d == '.ssh']
        for filename in files:
            filepath = os.path.join(root, filename)
            metadata = get_file_metadata(filepath)
            if metadata:
                results[filepath] = metadata
    return results


def build_baseline() -> dict:
    """Buat baseline semua file yang dimonitor"""
    logger.info('Membangun baseline FIM...')
    baseline = {}

    for path in CONFIG['monitored_paths']:
        if os.path.isfile(path):
            metadata = get_file_metadata(path)
            if metadata:
                baseline[path] = metadata
        elif os.path.isdir(path):
            dir_results = scan_directory(path)
            baseline.update(dir_results)

    # Simpan baseline
    os.makedirs(os.path.dirname(CONFIG['baseline_file']), exist_ok=True)
    with open(CONFIG['baseline_file'], 'w') as f:
        json.dump({
            'created': datetime.now().isoformat(),
            'files': baseline
        }, f, indent=2)

    logger.info(f'Baseline dibuat: {len(baseline)} file')
    return baseline


def load_baseline() -> dict:
    """Load baseline dari file"""
    if not os.path.exists(CONFIG['baseline_file']):
        logger.warning('Baseline tidak ada, membuat baseline baru...')
        return build_baseline()

    with open(CONFIG['baseline_file'], 'r') as f:
        data = json.load(f)
    return data['files']


def compare_with_baseline(current: dict, baseline: dict) -> dict:
    """Bandingkan kondisi saat ini dengan baseline"""
    changes = {
        'modified': [],
        'added': [],
        'deleted': [],
        'permission_changed': []
    }

    # Cek file yang dimodifikasi atau dihapus
    for filepath, old_meta in baseline.items():
        if filepath not in current:
            changes['deleted'].append(filepath)
            logger.warning(f'FILE DIHAPUS: {filepath}')
        else:
            new_meta = current[filepath]

            if new_meta['hash'] != old_meta['hash']:
                changes['modified'].append({
                    'path': filepath,
                    'old_hash': old_meta['hash'],
                    'new_hash': new_meta['hash'],
                    'old_mtime': old_meta['mtime'],
                    'new_mtime': new_meta['mtime']
                })
                logger.critical(f'FILE DIMODIFIKASI: {filepath}')

            if new_meta['permissions'] != old_meta['permissions']:
                changes['permission_changed'].append({
                    'path': filepath,
                    'old_perm': old_meta['permissions'],
                    'new_perm': new_meta['permissions']
                })
                logger.warning(f'PERMISSION BERUBAH: {filepath}')

    # Cek file baru yang tidak ada di baseline
    for filepath in current:
        if filepath not in baseline:
            changes['added'].append(filepath)
            logger.warning(f'FILE BARU: {filepath}')

    return changes


def send_alert(changes: dict):
    """Kirim email alert jika ada perubahan"""
    total_changes = sum(len(v) for v in changes.values())
    if total_changes == 0:
        return

    subject = f'[FIM ALERT] {total_changes} perubahan file terdeteksi - {datetime.now().strftime("%Y-%m-%d %H:%M")}'

    body = f"""ALERT: File Integrity Monitor
Waktu: {datetime.now().isoformat()}
Server: {os.uname().nodename}

=== RINGKASAN ===
File dimodifikasi: {len(changes['modified'])}
File baru: {len(changes['added'])}
File dihapus: {len(changes['deleted'])}
Permission berubah: {len(changes['permission_changed'])}

"""

    if changes['modified']:
        body += "=== FILE DIMODIFIKASI ===\n"
        for f in changes['modified']:
            body += f"  {f['path']}\n    Hash lama: {f['old_hash'][:16]}...\n    Hash baru: {f['new_hash'][:16]}...\n\n"

    if changes['deleted']:
        body += "=== FILE DIHAPUS ===\n"
        for f in changes['deleted']:
            body += f"  {f}\n"

    if changes['added']:
        body += "\n=== FILE BARU (tidak ada di baseline) ===\n"
        for f in changes['added']:
            body += f"  {f}\n"

    logger.critical(f'ALERT dikirim: {total_changes} perubahan')
    print(body)  # Juga print ke console / syslog


def run_check():
    """Jalankan satu siklus pengecekan"""
    logger.info('Mulai pengecekan FIM...')

    baseline = load_baseline()

    # Scan kondisi saat ini
    current = {}
    for path in CONFIG['monitored_paths']:
        if os.path.isfile(path):
            meta = get_file_metadata(path)
            if meta:
                current[path] = meta
        elif os.path.isdir(path):
            current.update(scan_directory(path))

    changes = compare_with_baseline(current, baseline)
    total = sum(len(v) for v in changes.values())

    if total > 0:
        logger.critical(f'Total {total} perubahan terdeteksi!')
        send_alert(changes)
    else:
        logger.info('Tidak ada perubahan terdeteksi.')

    return changes


if __name__ == '__main__':
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == 'baseline':
        print('Membangun baseline baru...')
        baseline = build_baseline()
        print(f'Baseline dibuat: {len(baseline)} file dipantau')
    else:
        print(f'FIM berjalan, interval: {CONFIG["check_interval"]}s')
        while True:
            changes = run_check()
            time.sleep(CONFIG['check_interval'])
```

**Penggunaan:**
```bash
# Buat baseline pertama kali:
python3 fim.py baseline

# Jalankan sebagai daemon:
python3 fim.py &

# Atau sebagai systemd service:
cat > /etc/systemd/system/fim.service << EOF
[Unit]
Description=File Integrity Monitor

[Service]
ExecStart=/usr/bin/python3 /opt/fim/fim.py
Restart=always

[Install]
WantedBy=multi-user.target
EOF
systemctl enable --now fim
```

